const html = $json.data;
const reelURL = $('On form submission').first().json.link;

if (!html || typeof html !== 'string') {
  throw new Error(
    'HTML não encontrado em $json.data'
  );
}

const marker =
  '"video_versions":[{"type":101,"url":"';

const start = html.indexOf(marker);

if (start === -1) {
  throw new Error(
    'video_versions não foi encontrado no HTML'
  );
}

const urlStart = start + marker.length;
const urlEnd = html.indexOf('"', urlStart);

if (urlEnd === -1) {
  throw new Error(
    'Não foi possível identificar o final da URL'
  );
}

const rawUrl = html.slice(urlStart, urlEnd);

let videoUrl;

try {
  videoUrl = JSON.parse(`"${rawUrl}"`);
} catch {
  videoUrl = rawUrl;
}

videoUrl = videoUrl
  .replace(/\\\//g, '/')
  .replace(/\\u0026/gi, '&')
  .replace(/\\u0025/gi, '%')
  .replace(/&amp;/g, '&');

if (
  !videoUrl.startsWith('https://') ||
  !videoUrl.includes('.mp4')
) {
  throw new Error(
    `A URL extraída não é um MP4 válido: ${videoUrl.slice(0, 200)}`
  );
}

return {
  json: {
    reels_link: reelURL,
    platform: 'instagram',
    video_url: videoUrl,
  },
};

const link = String($json.link ?? '').trim();

if (!link) {
  throw new Error('O campo link não foi informado');
}

const patterns = [
  // youtube.com/shorts/VIDEO_ID
  /(?:youtube\.com\/shorts\/)([a-zA-Z0-9_-]{11})/,

  // youtube.com/watch?v=VIDEO_ID
  /(?:youtube\.com\/watch\?.*?v=)([a-zA-Z0-9_-]{11})/,

  // youtu.be/VIDEO_ID
  /(?:youtu\.be\/)([a-zA-Z0-9_-]{11})/,

  // youtube.com/embed/VIDEO_ID
  /(?:youtube\.com\/embed\/)([a-zA-Z0-9_-]{11})/,

  // youtube.com/live/VIDEO_ID
  /(?:youtube\.com\/live\/)([a-zA-Z0-9_-]{11})/,

  // youtube.com/v/VIDEO_ID
  /(?:youtube\.com\/v\/)([a-zA-Z0-9_-]{11})/,
];

let videoId = null;

for (const pattern of patterns) {
  const match = link.match(pattern);

  if (match?.[1]) {
    videoId = match[1];
    break;
  }
}

// Aceita também o ID puro
if (
  !videoId &&
  /^[a-zA-Z0-9_-]{11}$/.test(link)
) {
  videoId = link;
}

if (!videoId) {
  throw new Error(
    `Não foi possível identificar o ID do vídeo: ${link}`
  );
}

return {
  json: {
    ...$json,
    video_id: videoId,
  },
};

const videos = $json.videos?.items ?? [];
const audios = $json.audios?.items ?? [];
const subtitles = $json.subtitles?.items ?? [];

/*
 * Vídeo MP4 que já contém áudio.
 */
const video =
  videos.find(item =>
    item.url &&
    item.extension === 'mp4' &&
    item.hasAudio === true
  ) ??
  videos.find(item =>
    item.url &&
    item.extension === 'mp4'
  ) ??
  videos[0];

/*
 * Melhor áudio M4A.
 */
const audio =
  audios
    .filter(item =>
      item.url &&
      item.extension === 'm4a'
    )
    .sort(
      (a, b) =>
        Number(b.size ?? 0) -
        Number(a.size ?? 0)
    )[0] ??
  audios.find(item => item.url);

/*
 * Prioriza legenda em português.
 */
const subtitle =
  subtitles.find(item => item.code === 'pt-BR') ??
  subtitles.find(item => item.code === 'pt') ??
  subtitles[0];

if (!subtitle?.url) {
  throw new Error(
    'O vídeo não possui legenda disponível'
  );
}

const separator =
  subtitle.url.includes('?') ? '&' : '?';

return {
  json: {
    platform: 'youtube',

    video_id: $json.id,
    title: $json.title,

    youtube_url:
      `https://www.youtube.com/watch?v=${$json.id}`,

    video_url: video?.url ?? null,
    video_quality: video?.quality ?? null,
    video_extension: video?.extension ?? null,
    video_size: video?.size ?? null,
    video_size_text: video?.sizeText ?? null,

    audio_url: audio?.url ?? null,
    audio_extension: audio?.extension ?? null,
    audio_mime_type: audio?.mimeType ?? null,
    audio_size: audio?.size ?? null,
    audio_size_text: audio?.sizeText ?? null,

    subtitle_url:
      `${subtitle.url}${separator}fmt=json3`,
    subtitle_language: subtitle.code ?? null,
    subtitle_type: subtitle.text ?? null,

    media_expiration:
      $json.audios?.expiration ??
      $json.videos?.expiration ??
      null,

    subtitle_expiration:
      $json.subtitles?.expiration ?? null,
  },
};

const media =
  $('Seleciona midias').item.json;

const raw =
  $json.data ??
  $json.body ??
  $json;

if (
  raw === null ||
  raw === undefined ||
  raw === ''
) {
  throw new Error(
    'O YouTube retornou a legenda vazia'
  );
}

let captionData = raw;

if (typeof captionData === 'string') {
  const trimmed = captionData.trim();

  if (!trimmed) {
    throw new Error(
      'O conteúdo da legenda está vazio'
    );
  }

  try {
    captionData = JSON.parse(trimmed);
  } catch {
    throw new Error(
      `Resposta de legenda inválida: ${trimmed.slice(0, 300)}`
    );
  }
}

const events = captionData.events ?? [];

if (!Array.isArray(events) || !events.length) {
  throw new Error(
    'Nenhum evento de legenda foi retornado'
  );
}

function formatTime(milliseconds) {
  const totalSeconds = Math.floor(
    Number(milliseconds ?? 0) / 1000
  );

  const hours = Math.floor(
    totalSeconds / 3600
  );

  const minutes = Math.floor(
    (totalSeconds % 3600) / 60
  );

  const seconds = totalSeconds % 60;

  if (hours > 0) {
    return [
      hours,
      minutes,
      seconds,
    ]
      .map(value =>
        String(value).padStart(2, '0')
      )
      .join(':');
  }

  return [
    minutes,
    seconds,
  ]
    .map(value =>
      String(value).padStart(2, '0')
    )
    .join(':');
}

const segments = events
  .filter(event => Array.isArray(event.segs))
  .map(event => {
    const text = event.segs
      .map(segment => segment.utf8 ?? '')
      .join('')
      .replace(/\n/g, ' ')
      .replace(/\s+/g, ' ')
      .trim();

    return {
      start_ms: Number(event.tStartMs ?? 0),
      duration_ms: Number(
        event.dDurationMs ?? 0
      ),
      timestamp: formatTime(
        event.tStartMs
      ),
      text,
    };
  })
  .filter(segment => segment.text);

const uniqueSegments = segments.filter(
  (segment, index, array) =>
    index === 0 ||
    segment.text !== array[index - 1].text
);

const transcription = uniqueSegments
  .map(segment => segment.text)
  .join(' ')
  .replace(/\s+/g, ' ')
  .trim();

const transcriptionWithTimestamps =
  uniqueSegments
    .map(
      segment =>
        `[${segment.timestamp}] ${segment.text}`
    )
    .join('\n');

return {
  json: {
    ...media,

    transcription,
    transcription_with_timestamps:
      transcriptionWithTimestamps,

    segments: uniqueSegments,
    total_segments: uniqueSegments.length,
  },
};
